# Scorecard Dashboard
band_order  = ["High Risk", "Very Poor", "Poor", "Fair", "Good", "Excellent"]
band_colors = ["#8e44ad", "#e74c3c", "#e67e22", "#f39c12", "#2ecc71", "#27ae60"]

